var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…쿨럭…","JPN":"……ゲホッ……","ENG":"…*Cough…*","TWN":"…咳…"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"공기가 차고, 몸이 무겁군.","JPN":"空気が冷たく、体が重い。","ENG":"The air is cold, and my body feels heavy.","TWN":"空氣很冷，身體很沉重。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"지치고, 두려운가?","JPN":"疲弊し、怯えているか？","ENG":"Tired? Afraid?","TWN":"感到疲憊和恐懼嗎？"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BELL6"},{"id":"L6_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"충분히 지쳤지. 또한 충분히 두렵기도 하고.","JPN":"十分疲れた。そして十分怯えている。","ENG":"Tired enough. And yes, afraid enough, too.","TWN":"我已經很累了。也感到很恐懼。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"허나 그러하기에… 나의 정신은 그 어느 때보다 맑다네.","JPN":"しかし、だからこそ……某の頭はいつになく冴えている。","ENG":"But because of that… my mind is clearer than ever.","TWN":"但正因為如此… 我的精神比任何時候都更清醒。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"연화의 혼백은 이 차디찬 색의 풍경에 갇혀, 긴 세월을 보냈겠지.","JPN":"レンカの魂魄はこの凍てつく色彩の風景に閉じ込められて、長い時間を過ごしたのだろう。","ENG":"Yeonhwa's soul must've been trapped in this bleak, colorless place for a long, long time.","TWN":"蓮華的魂魄被困在這個冰冷的風景中，度過了漫長的歲月吧。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"네놈의 먹처럼 시커먼 마수가 그녀의 심상을 검게 물들일 때까지 말이다.","JPN":"貴様の墨のような手が彼女の心象を黒く染めてしまうまで。","ENG":"Until your inky black claws stained every corner of her spirit.","TWN":"直到你那像墨水一樣漆黑的魔掌，將她的心靈染黑為止。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"생은 찰나요, 죽음은 영원이라.","JPN":"生は刹那、死は永遠なり。","ENG":"Life is but a fleeting moment. Death is eternal.","TWN":"生命轉瞬即逝，死亡卻是永恆。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BELL6"},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"찰나보다 영원을 받아들이는 것이 어찌 나쁘다고 할까.","JPN":"刹那より永遠を選ぶことの、何が悪いというのだ。","ENG":"So what harm is there in choosing eternity over the fleeting?","TWN":"接受永恆，怎會比接受轉瞬即逝的生命還要糟糕。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"사람을 잡아먹더니, 그 뻔뻔함까지 집어삼켰군.","JPN":"人を食らったやつらしく、図々しさも人に似ているな。","ENG":"You devoured humans, and you seemed to have swallowed their shamelessness too.","TWN":"你吞噬了人類，連那份厚顏無恥也一併吞噬了嗎。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"언제까지 그늘에 숨어 실없는 궤변이나 늘어놓을 셈이냐?","JPN":"いつまで影に隠れ、くだらない詭弁を並べるつもりだ？","ENG":"How long will you hide in the shadows, spouting hollow nonsense?","TWN":"你打算躲在陰影裡，說這些無聊的詭辯到什麼時候？"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"본좌가 너를 살피니, 그 명줄이 경각에 달하였구나.","JPN":"吾輩がお前を見たところ、その命は風前の灯火に等しい。","ENG":"I can see it now. That life of yours is hanging by a breath.","TWN":"本座觀察你，發現你的生命只剩下片刻。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"피에 깃든 힘을 한 번이라도 더 쓴다면, 그대로 명을 다하고 죽겠지.","JPN":"血に宿る力をあと一度使えば、お前の命は尽きるであろう。","ENG":"One more use of the blood-born power, and you'll die.","TWN":"如果你再使用一次那血中的力量，你的性命就會終結。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"알고 있네.","JPN":"分かっている。","ENG":"I'm well aware.","TWN":"我知道。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"처음부터 본좌와 그 목숨을 맞바꾸러 왔다는 건가? 배짱 한 번 좋구나.","JPN":"最初から命を捨てる覚悟で吾輩のもとに来たというのか。中々の度胸ではないか。","ENG":"So you came here intending to trade your life for mine? Bold of you.","TWN":"你從一開始，就打算用你的性命來換本座的性命嗎？膽子真大。"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BELL6"},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"그 하잘 것 없는 목숨의 무게로 이 몸을 짓누를 순 없을 테지만 말이다.","JPN":"その儚い命の重さで吾輩の体を潰すことは出来ぬだろうがな。","ENG":"Though that pitiful life won't be nearly enough to weigh down this body.","TWN":"但你那微不足道的性命，是無法壓垮我的。"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이빨은 이미 마중을 나왔는데 혀만 길어지니 참으로 덧없군.","JPN":"牙をさらけ出しておきながら無駄口が多いな。","ENG":"The fangs are already bared, yet you keep wagging your tongue. What a waste.","TWN":"牙齒都已經探出來了，舌頭還這麼長，真是可悲。"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이제 그만, 이 지긋지긋한 번뇌에 종지부를 찍도록 하지.","JPN":"いい加減このうんざりとした煩悩に、終止符を打つとしよう。","ENG":"Let's end this. Right here and now.","TWN":"現在，我們就為這無止盡的煩惱畫下句點吧。"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};